   VEDANA · Housekeeping QR Report
   Design: Clean, elder-friendly, blue-toned mobile-first UI
   Font: Nunito (Google Fonts)
   ============================================================ */

/* ── Reset & Base ─────────────────────────────────────────── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --font: 'Nunito', sans-serif;

  /* Brand */
  --blue:       #4A90FF;
  --blue-dark:  #3478E4;
  --blue-light: #E8F4FF;
  --blue-pale:  #F0F7FF;

  /* Neutrals */
  --ink:        #111111;
  --ink-mid:    #333333;
  --ink-muted:  #6B7280;
  --border:     #E5ECF6;
  --bg:         #F8F9FB;
  --white:      #FFFFFF;

  /* Semantic */
  --success:    #22C55E;
  --error:      #EF4444;

  /* Card shadows */
  --shadow-card: 0 8px 24px rgba(74, 144, 255, 0.12);
  --shadow-btn:  0 4px 16px rgba(74, 144, 255, 0.35);
  --shadow-sm:   0 2px 8px rgba(0,0,0,0.08);

  /* Radii (LOCKED – do not change) */
  --r-card:   20px;
  --r-card-s: 16px;
  --r-thumb:  14px;
  --r-btn:    26px;
  --r-icon:   50%;
  --r-pill:   999px;

  /* Transition */
  --t-fast:   150ms ease;
  --t-normal: 280ms ease;
  --t-slide:  300ms cubic-bezier(.4,0,.2,1);
}

html, body {
  height: 100%;
  width: 100%;
  overflow: hidden;
  font-family: var(--font);
  background: var(--bg);
  color: var(--ink-mid);
  line-height: 1.55;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* ── Screen Management ────────────────────────────────────── */
.screen {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  background: linear-gradient(160deg, #F8F9FB 0%, #FFFFFF 100%);
  overflow: hidden;

  /* off-screen to the right */
  transform: translateX(100%);
  opacity: 0;
  transition: transform var(--t-slide), opacity var(--t-slide);
  will-change: transform, opacity;
  z-index: 1;
}

.screen.active {
  transform: translateX(0);
  opacity: 1;
  z-index: 2;
}

.screen.slide-out {
  transform: translateX(-30%);
  opacity: 0;
  z-index: 1;
}

/* ── Sticky Header (shared) ───────────────────────────────── */
.sticky-header {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 16px 12px;
  background: rgba(248, 249, 251, 0.95);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  z-index: 10;
}

.header-center {
  flex: 1;
  min-width: 0;
}

/* ── Buttons ──────────────────────────────────────────────── */
.btn-back {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border-radius: var(--r-icon);
  background: var(--white);
  border: none;
  cursor: pointer;
  color: var(--ink-mid);
  box-shadow: var(--shadow-sm);
  flex-shrink: 0;
  transition: transform var(--t-fast), box-shadow var(--t-fast);
  -webkit-tap-highlight-color: transparent;
}
.btn-back:active { transform: scale(0.93); }

.btn-primary {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  width: calc(100% - 32px);
  margin: 0 auto;
  height: 52px;
  border-radius: var(--r-btn);
  background: var(--blue);
  color: var(--white);
  font-family: var(--font);
  font-size: 16px;
  font-weight: 800;
  letter-spacing: 0.3px;
  border: none;
  cursor: pointer;
  box-shadow: var(--shadow-btn);
  transition: transform var(--t-fast), background var(--t-fast), box-shadow var(--t-fast);
  -webkit-tap-highlight-color: transparent;
}
.btn-primary:active {
  transform: scale(0.97);
  background: var(--blue-dark);
  box-shadow: 0 2px 8px rgba(74,144,255,0.25);
}

.btn-ghost {
  display: block;
  width: calc(100% - 32px);
  margin: 12px auto 0;
  height: 44px;
  border-radius: var(--r-btn);
  background: transparent;
  color: var(--ink-muted);
  font-family: var(--font);
  font-size: 14px;
  font-weight: 600;
  border: 1.5px solid var(--border);
  cursor: pointer;
  transition: background var(--t-fast), color var(--t-fast);
  -webkit-tap-highlight-color: transparent;
}
.btn-ghost:active {
  background: var(--blue-pale);
  color: var(--blue);
}

.btn-icon-sm {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 48px;
  height: 48px;
  border-radius: var(--r-icon);
  background: rgba(255,255,255,0.85);
  border: none;
  cursor: pointer;
  color: var(--ink-mid);
  box-shadow: var(--shadow-sm);
  transition: transform var(--t-fast), background var(--t-fast);
  -webkit-tap-highlight-color: transparent;
}
.btn-icon-sm:active { transform: scale(0.9); }

.btn-continue {
  background: var(--blue);
  color: var(--white);
  box-shadow: var(--shadow-btn);
}
.btn-continue:active {
  transform: scale(0.9);
  background: var(--blue-dark);
}

/* ── Typography ───────────────────────────────────────────── */
.page-title {
  font-size: 18px;
  font-weight: 800;
  color: var(--ink);
  line-height: 1.3;
}

.page-subtitle {
  font-size: 13px;
  font-weight: 600;
  color: var(--ink-muted);
  margin-top: 2px;
}

.room-badge {
  font-size: 16px;
  font-weight: 900;
  color: var(--blue);
  letter-spacing: 1px;
  line-height: 1.2;
}

.section-label {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  font-weight: 700;
  color: var(--ink-muted);
  text-transform: uppercase;
  letter-spacing: 0.6px;
  margin-bottom: 12px;
}

.hint-text {
  font-size: 13px;
  color: var(--ink-muted);
  text-align: center;
  font-weight: 600;
  margin: 16px 16px 24px;
}

/* ── Cards ────────────────────────────────────────────────── */
.card {
  margin: 0 16px;
  background: var(--white);
  border-radius: var(--r-card-s);
  padding: 16px;
  box-shadow: var(--shadow-sm);
  border: 1px solid var(--border);
}

.card--main {
  background: var(--blue-light);
  border-color: rgba(74,144,255,0.2);
  box-shadow: var(--shadow-card);
}

/* ── SCREEN 1 · QR SCAN ───────────────────────────────────── */
.screen-inner {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  padding-bottom: 32px;
  -webkit-overflow-scrolling: touch;
}

.qr-header {
  padding: 40px 16px 20px;
  text-align: center;
}

.app-logo {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 56px;
  height: 56px;
  background: var(--blue-pale);
  border-radius: 18px;
  margin-bottom: 16px;
  box-shadow: var(--shadow-card);
}

.scanner-wrapper {
  padding: 0 24px;
  margin-bottom: 16px;
}

.scanner-frame {
  position: relative;
  width: 100%;
  aspect-ratio: 3 / 4;
  max-height: 340px;
  background: #0d0d0d;
  border-radius: var(--r-card);
  overflow: hidden;
  box-shadow: 0 12px 40px rgba(0,0,0,0.25);
}

.scanner-frame video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.scanner-overlay {
  position: absolute;
  inset: 0;
  pointer-events: none;
}

/* Corner brackets */
.corner {
  position: absolute;
  width: 32px;
  height: 32px;
  border-color: white;
  border-style: solid;
  border-width: 0;
}
.corner.tl { top: 20px; left: 20px; border-top-width: 3px; border-left-width: 3px; border-radius: 4px 0 0 0; }
.corner.tr { top: 20px; right: 20px; border-top-width: 3px; border-right-width: 3px; border-radius: 0 4px 0 0; }
.corner.bl { bottom: 20px; left: 20px; border-bottom-width: 3px; border-left-width: 3px; border-radius: 0 0 0 4px; }
.corner.br { bottom: 20px; right: 20px; border-bottom-width: 3px; border-right-width: 3px; border-radius: 0 0 4px 0; }

/* Pulse animation on corners */
@keyframes corner-pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}
.scanner-frame.scanning .corner {
  animation: corner-pulse 1.2s ease-in-out infinite;
}

/* Scan line */
.scan-line {
  position: absolute;
  left: 20px;
  right: 20px;
  height: 2px;
  background: linear-gradient(90deg, transparent, var(--blue), transparent);
  border-radius: 2px;
  top: 50%;
  animation: scan-move 2s ease-in-out infinite;
  display: none;
}
.scanner-frame.scanning .scan-line { display: block; }

@keyframes scan-move {
  0% { top: 20%; opacity: 0.5; }
  50% { opacity: 1; }
  100% { top: 80%; opacity: 0.5; }
}

.scanner-status {
  position: absolute;
  bottom: 12px;
  left: 0; right: 0;
  text-align: center;
  font-size: 13px;
  font-weight: 700;
  color: rgba(255,255,255,0.85);
  font-family: var(--font);
}

/* ── SCREEN 2 · CAMERA ────────────────────────────────────── */
.camera-view-wrapper {
  position: relative;
  flex: 1;
  background: #000;
  overflow: hidden;
  min-height: 0;
}

.camera-view-wrapper video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.cam-guide-text {
  position: absolute;
  bottom: 12px;
  left: 0; right: 0;
  text-align: center;
  font-size: 13px;
  font-weight: 700;
  color: rgba(255,255,255,0.8);
  font-family: var(--font);
  text-shadow: 0 1px 4px rgba(0,0,0,0.5);
  pointer-events: none;
}

/* Counter badge */
.counter-badge {
  font-size: 13px;
  font-weight: 800;
  color: var(--blue);
  background: var(--blue-pale);
  border-radius: var(--r-pill);
  padding: 4px 10px;
  white-space: nowrap;
  flex-shrink: 0;
}

/* Thumbnails */
.thumbnail-row {
  display: flex;
  gap: 10px;
  padding: 12px 16px;
  overflow-x: auto;
  flex-shrink: 0;
  background: var(--bg);
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
}
.thumbnail-row::-webkit-scrollbar { display: none; }

.thumb-placeholder {
  width: 68px;
  height: 68px;
  border-radius: var(--r-thumb);
  border: 2px dashed var(--border);
  flex-shrink: 0;
  background: var(--white);
}

.thumb-item {
  position: relative;
  width: 68px;
  height: 68px;
  border-radius: var(--r-thumb);
  overflow: visible;
  flex-shrink: 0;
  box-shadow: var(--shadow-sm);
}
.thumb-item img {
  width: 68px;
  height: 68px;
  border-radius: var(--r-thumb);
  object-fit: cover;
  display: block;
}
.thumb-item .thumb-delete {
  position: absolute;
  top: -6px;
  right: -6px;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: var(--error);
  border: 2px solid var(--white);
  color: var(--white);
  font-size: 13px;
  line-height: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  font-weight: 900;
  z-index: 5;
  -webkit-tap-highlight-color: transparent;
}

/* Camera controls */
.camera-controls {
  display: flex;
  align-items: center;
  justify-content: space-around;
  padding: 16px 24px 24px;
  background: var(--bg);
  flex-shrink: 0;
}

.btn-shutter {
  position: relative;
  width: 76px;
  height: 76px;
  border-radius: 50%;
  background: transparent;
  border: 4px solid var(--blue);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform var(--t-fast);
  -webkit-tap-highlight-color: transparent;
}
.btn-shutter:active { transform: scale(0.93); }

.shutter-dot {
  width: 56px;
  height: 56px;
  border-radius: 50%;
  background: var(--blue);
  transition: transform var(--t-fast), background var(--t-fast);
}
.btn-shutter:active .shutter-dot {
  transform: scale(0.88);
  background: var(--blue-dark);
}

@keyframes shutter-flash {
  0% { opacity: 0; }
  30% { opacity: 0.9; }
  100% { opacity: 0; }
}
.cam-flash {
  position: fixed;
  inset: 0;
  background: white;
  pointer-events: none;
  z-index: 100;
  opacity: 0;
  animation: shutter-flash 0.35s ease-out forwards;
}

/* ── SCREEN 3 · REPORT ────────────────────────────────────── */
.report-scroll {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding: 16px 0;
  -webkit-overflow-scrolling: touch;
}

.photo-strip {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  padding: 2px 2px 6px;
  scrollbar-width: none;
  -webkit-overflow-scrolling: touch;
}
.photo-strip::-webkit-scrollbar { display: none; }

.photo-strip-item {
  position: relative;
  width: 80px;
  height: 80px;
  border-radius: var(--r-thumb);
  overflow: hidden;
  flex-shrink: 0;
  box-shadow: var(--shadow-sm);
}
.photo-strip-item img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* Voice recording */
.voice-center {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  padding: 8px 0 4px;
}

/* Waveform */
.waveform {
  display: flex;
  align-items: center;
  gap: 4px;
  height: 32px;
}
.waveform span {
  display: block;
  width: 4px;
  background: var(--blue);
  border-radius: 4px;
  height: 8px;
  opacity: 0.3;
  transform-origin: center bottom;
}
.waveform.active span {
  opacity: 1;
  animation: wave 0.8s ease-in-out infinite;
}
.waveform.active span:nth-child(1)  { animation-delay: 0.0s; }
.waveform.active span:nth-child(2)  { animation-delay: 0.1s; }
.waveform.active span:nth-child(3)  { animation-delay: 0.2s; }
.waveform.active span:nth-child(4)  { animation-delay: 0.15s; }
.waveform.active span:nth-child(5)  { animation-delay: 0.05s; }
.waveform.active span:nth-child(6)  { animation-delay: 0.25s; }
.waveform.active span:nth-child(7)  { animation-delay: 0.1s; }
.waveform.active span:nth-child(8)  { animation-delay: 0.2s; }
.waveform.active span:nth-child(9)  { animation-delay: 0.35s; }
.waveform.active span:nth-child(10) { animation-delay: 0.05s; }

@keyframes wave {
  0%, 100% { height: 8px; }
  50% { height: 28px; }
}

.btn-mic {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  background: var(--blue);
  color: white;
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 6px 20px rgba(74,144,255,0.4);
  transition: transform var(--t-fast), background var(--t-fast), box-shadow var(--t-fast);
  -webkit-tap-highlight-color: transparent;
}
.btn-mic:active { transform: scale(0.93); }
.btn-mic.recording {
  background: var(--error);
  box-shadow: 0 6px 20px rgba(239,68,68,0.4);
  animation: mic-pulse 1.2s ease-in-out infinite;
}
@keyframes mic-pulse {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.05); }
}

.mic-label {
  font-size: 13px;
  font-weight: 700;
  color: var(--ink-muted);
  text-align: center;
}

.voice-transcript {
  width: 100%;
  border: 1.5px solid rgba(74,144,255,0.25);
  border-radius: 12px;
  padding: 12px;
  font-family: var(--font);
  font-size: 14px;
  font-weight: 600;
  color: var(--ink-mid);
  background: rgba(255,255,255,0.7);
  resize: none;
  line-height: 1.6;
  outline: none;
  transition: border-color var(--t-fast);
  margin-top: 4px;
}
.voice-transcript:focus { border-color: var(--blue); }
.voice-transcript::placeholder { color: var(--ink-muted); font-weight: 400; }

.error-banner {
  margin: 0 16px;
  padding: 12px 16px;
  border-radius: 12px;
  background: #FEF2F2;
  border: 1px solid #FECACA;
  color: var(--error);
  font-size: 14px;
  font-weight: 600;
}

/* Sticky CTA */
.sticky-cta {
  padding: 12px 16px 24px;
  background: rgba(248,249,251,0.97);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-top: 1px solid var(--border);
  flex-shrink: 0;
}

.btn-submit {
  width: 100%;
  margin: 0;
}

/* ── SCREEN 4 · SUCCESS ───────────────────────────────────── */
.success-wrapper {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 40px 24px;
  text-align: center;
  gap: 0;
}

.success-anim {
  position: relative;
  width: 120px;
  height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 28px;
}

.success-ring {
  position: absolute;
  border-radius: 50%;
  animation: ring-grow 0.6s ease-out forwards;
  opacity: 0;
}
.r1 {
  width: 120px; height: 120px;
  background: rgba(74,144,255,0.08);
  animation-delay: 0.2s;
}
.r2 {
  width: 96px; height: 96px;
  background: rgba(74,144,255,0.14);
  animation-delay: 0.1s;
}

@keyframes ring-grow {
  0% { transform: scale(0.5); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

.success-circle {
  width: 76px;
  height: 76px;
  border-radius: 50%;
  background: linear-gradient(135deg, #4AAEFF, #4A90FF);
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 8px 28px rgba(74,144,255,0.4);
  animation: check-pop 0.45s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
  transform: scale(0);
}
@keyframes check-pop {
  0% { transform: scale(0); }
  100% { transform: scale(1); }
}

.success-title {
  font-size: 26px;
  font-weight: 900;
  color: var(--ink);
  line-height: 1.2;
  margin-bottom: 8px;
  animation: fade-up 0.4s ease 0.3s both;
}

.success-room {
  font-size: 15px;
  font-weight: 900;
  color: var(--blue);
  letter-spacing: 1.5px;
  margin-bottom: 12px;
  animation: fade-up 0.4s ease 0.35s both;
}

.success-sub {
  font-size: 14px;
  font-weight: 600;
  color: var(--ink-muted);
  line-height: 1.6;
  margin-bottom: 24px;
  animation: fade-up 0.4s ease 0.4s both;
}

@keyframes fade-up {
  0% { opacity: 0; transform: translateY(12px); }
  100% { opacity: 1; transform: translateY(0); }
}

.success-chips {
  display: flex;
  gap: 10px;
  margin-bottom: 32px;
  animation: fade-up 0.4s ease 0.45s both;
}

.chip {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 13px;
  font-weight: 700;
  color: var(--blue);
  background: var(--blue-pale);
  border-radius: var(--r-pill);
  padding: 6px 14px;
}

.btn-new-room {
  animation: fade-up 0.4s ease 0.5s both;
}

.redirect-hint {
  margin-top: 16px;
  font-size: 13px;
  font-weight: 600;
  color: var(--ink-muted);
  animation: fade-up 0.4s ease 0.55s both;
}

/* ── TOAST ────────────────────────────────────────────────── */
.toast {
  position: fixed;
  bottom: 24px;
  left: 50%;
  transform: translateX(-50%) translateY(120%);
  background: rgba(17,17,17,0.9);
  color: white;
  padding: 12px 24px;
  border-radius: var(--r-pill);
  font-size: 14px;
  font-weight: 700;
  font-family: var(--font);
  z-index: 9999;
  transition: transform 0.3s cubic-bezier(.4,0,.2,1);
  white-space: nowrap;
  max-width: calc(100vw - 48px);
  text-align: center;
  pointer-events: none;
  backdrop-filter: blur(8px);
}
.toast.show { transform: translateX(-50%) translateY(0); }

/* ── LOADER ───────────────────────────────────────────────── */
.loader-overlay {
  position: fixed;
  inset: 0;
  background: rgba(255,255,255,0.85);
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
  z-index: 8888;
  display: flex;
  align-items: center;
  justify-content: center;
}

.loader-card {
  background: var(--white);
  border-radius: var(--r-card);
  padding: 32px 40px;
  box-shadow: var(--shadow-card);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 16px;
}

.loader-spin {
  width: 40px;
  height: 40px;
  border: 4px solid var(--blue-light);
  border-top-color: var(--blue);
  border-radius: 50%;
  animation: spin 0.75s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

.loader-label {
  font-size: 14px;
  font-weight: 700;
  color: var(--ink-muted);
}

/* ── Mobile safety ────────────────────────────────────────── */
@supports (padding-top: env(safe-area-inset-top)) {
  .sticky-header {
    padding-top: calc(14px + env(safe-area-inset-top));
  }
  .qr-header {
    padding-top: calc(40px + env(safe-area-inset-top));
  }
  .sticky-cta {
    padding-bottom: calc(24px + env(safe-area-inset-bottom));
  }
  .camera-controls {
    padding-bottom: calc(24px + env(safe-area-inset-bottom));
  }
}
