/**
 * Vedana · Housekeeping QR Report
 * Main application logic – 4 screen SPA
 */

// ── State ─────────────────────────────────────────────────────
const state = {
  currentRoom: '',
  photos: [],          // Array of { blob, dataUrl, uploadedUrl }
  isRecording: false,
  recognition: null,
  qrStream: null,
  cameraStream: null,
  facingMode: 'environment',
  qrScanInterval: null,
  redirectTimer: null,
};

// ── Init ──────────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  navigateTo('screen-qr');
});

// ── Screen navigation ─────────────────────────────────────────
function navigateTo(screenId) {
  const current = document.querySelector('.screen.active');
  const next = document.getElementById(screenId);
  if (!next || current === next) return;

  if (current) {
    current.classList.remove('active');
    current.classList.add('slide-out');
    setTimeout(() => current.classList.remove('slide-out'), 350);
  }

  next.classList.add('active');

  // Screen-specific setup
  if (screenId === 'screen-camera') setupCameraScreen();
  if (screenId === 'screen-report') setupReportScreen();
  if (screenId === 'screen-success') setupSuccessScreen();
  if (screenId === 'screen-qr') stopAllStreams();
}

function goBack(targetScreenId) {
  const current = document.querySelector('.screen.active');
  const target = document.getElementById(targetScreenId);
  if (!target || current === target) return;

  if (current) {
    current.classList.remove('active');
    // slide out to the right
    current.style.transform = 'translateX(100%)';
    current.style.opacity = '0';
    setTimeout(() => {
      current.style.transform = '';
      current.style.opacity = '';
    }, 350);
  }

  target.classList.add('active');
  target.classList.remove('slide-out');

  if (targetScreenId === 'screen-qr') stopAllStreams();
}

// ── Utilities ─────────────────────────────────────────────────
function escapeHtml(text) {
  const d = document.createElement('div');
  d.textContent = text ?? '';
  return d.innerHTML;
}

function showToast(msg, duration = 2800) {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.classList.add('show');
  clearTimeout(t._timer);
  t._timer = setTimeout(() => t.classList.remove('show'), duration);
}

function showLoader(show) {
  document.getElementById('loader').style.display = show ? 'flex' : 'none';
}

function stopAllStreams() {
  if (state.qrStream) {
    state.qrStream.getTracks().forEach(t => t.stop());
    state.qrStream = null;
  }
  if (state.cameraStream) {
    state.cameraStream.getTracks().forEach(t => t.stop());
    state.cameraStream = null;
  }
  clearInterval(state.qrScanInterval);
}

// ── SCREEN 1 · QR SCAN ────────────────────────────────────────
async function startQRScan() {
  const frame = document.getElementById('scanner-frame');
  const video = document.getElementById('qr-video');
  const status = document.getElementById('scanner-status');
  const btn = document.getElementById('btn-start-scan');

  try {
    if (state.qrStream) {
      state.qrStream.getTracks().forEach(t => t.stop());
    }

    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: 'environment', width: { ideal: 640 }, height: { ideal: 480 } }
    });
    state.qrStream = stream;
    video.srcObject = stream;
    await video.play();

    frame.classList.add('scanning');
    status.textContent = 'Đang quét…';
    btn.textContent = 'Đang quét…';
    btn.disabled = true;

    // Load jsQR dynamically
    if (!window.jsQR) {
      await loadScript('https://cdn.jsdelivr.net/npm/jsqr@1.4.0/dist/jsQR.js');
    }

    const canvas = document.getElementById('qr-canvas');
    const ctx = canvas.getContext('2d');

    clearInterval(state.qrScanInterval);
    state.qrScanInterval = setInterval(() => {
      if (video.readyState < video.HAVE_ENOUGH_DATA) return;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      ctx.drawImage(video, 0, 0);
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const code = window.jsQR(imageData.data, imageData.width, imageData.height);
      if (code && code.data) {
        onQRDetected(code.data);
      }
    }, 250);

  } catch (err) {
    showToast('Không thể truy cập camera: ' + err.message);
    btn.disabled = false;
    btn.textContent = 'Bắt đầu quét';
  }
}

function loadScript(src) {
  return new Promise((resolve, reject) => {
    const s = document.createElement('script');
    s.src = src;
    s.onload = resolve;
    s.onerror = reject;
    document.head.appendChild(s);
  });
}

function onQRDetected(data) {
  clearInterval(state.qrScanInterval);
  if (state.qrStream) {
    state.qrStream.getTracks().forEach(t => t.stop());
    state.qrStream = null;
  }

  // Extract room ID from QR (accept "PHONG_401", "ROOM 401", or plain "401", etc.)
  const roomMatch = data.match(/(\d{3,}|\w+-\w+)/);
  state.currentRoom = roomMatch ? roomMatch[0].toUpperCase() : data.toUpperCase().slice(0, 20);
  state.photos = [];

  document.getElementById('camera-room-title').textContent = 'PHÒNG ' + state.currentRoom;
  document.getElementById('report-room-title').textContent = 'PHÒNG ' + state.currentRoom;

  navigateTo('screen-camera');
}

function devSkipQR() {
  state.currentRoom = '401';
  state.photos = [];
  document.getElementById('camera-room-title').textContent = 'PHÒNG 401';
  document.getElementById('report-room-title').textContent = 'PHÒNG 401';
  navigateTo('screen-camera');
}

// ── SCREEN 2 · CAMERA ─────────────────────────────────────────
async function setupCameraScreen() {
  renderThumbnails();
  updateCounter();
  await startCameraFeed();
}

async function startCameraFeed() {
  const video = document.getElementById('camera-video');
  try {
    if (state.cameraStream) {
      state.cameraStream.getTracks().forEach(t => t.stop());
    }
    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: { ideal: state.facingMode }, width: { ideal: 1280 }, height: { ideal: 960 } },
      audio: false,
    });
    state.cameraStream = stream;
    video.srcObject = stream;
    await video.play();
  } catch (err) {
    showToast('Không thể mở camera: ' + err.message);
  }
}

async function switchCamera() {
  state.facingMode = state.facingMode === 'environment' ? 'user' : 'environment';
  await startCameraFeed();
}

function capturePhoto() {
  if (state.photos.length >= 3) {
    showToast('Tối đa 3 ảnh');
    return;
  }

  const video = document.getElementById('camera-video');
  const canvas = document.createElement('canvas');
  canvas.width = video.videoWidth || 640;
  canvas.height = video.videoHeight || 480;
  const ctx = canvas.getContext('2d');

  // Mirror front camera
  if (state.facingMode === 'user') {
    ctx.translate(canvas.width, 0);
    ctx.scale(-1, 1);
  }
  ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

  // Flash effect
  const flash = document.createElement('div');
  flash.className = 'cam-flash';
  document.body.appendChild(flash);
  setTimeout(() => flash.remove(), 400);

  canvas.toBlob(blob => {
    const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
    state.photos.push({ blob, dataUrl, uploadedUrl: null });
    renderThumbnails();
    updateCounter();

    if (state.photos.length === 3) {
      setTimeout(() => goToReport(), 600);
    }
  }, 'image/jpeg', 0.85);
}

function deletePhoto(index) {
  state.photos.splice(index, 1);
  renderThumbnails();
  updateCounter();
}

function renderThumbnails() {
  const row = document.getElementById('thumbnail-row');
  const placeholders = 3 - state.photos.length;

  const thumbsHtml = state.photos.map((p, i) => `
    <div class="thumb-item">
      <img src="${escapeHtml(p.dataUrl)}" alt="Ảnh ${i + 1}" />
      <span class="thumb-delete" onclick="deletePhoto(${i})">×</span>
    </div>
  `).join('');

  const placeholderHtml = Array.from({ length: placeholders }, () =>
    `<div class="thumb-placeholder"></div>`
  ).join('');

  row.innerHTML = thumbsHtml + placeholderHtml;
}

function updateCounter() {
  document.getElementById('photo-counter').textContent = `${state.photos.length} / 3`;
  const continueBtn = document.getElementById('btn-continue-report');
  continueBtn.style.opacity = state.photos.length >= 1 ? '1' : '0.4';
}

function goToReport() {
  if (state.photos.length < 1) {
    showToast('Cần ít nhất 1 ảnh để tiếp tục');
    return;
  }
  navigateTo('screen-report');
}

// ── SCREEN 3 · REPORT ─────────────────────────────────────────
function setupReportScreen() {
  // Stop camera to save battery
  if (state.cameraStream) {
    state.cameraStream.getTracks().forEach(t => t.stop());
    state.cameraStream = null;
  }

  renderPhotoStrip();
  document.getElementById('voice-transcript').value = '';
  document.getElementById('report-error').style.display = 'none';
  resetMicUI();
}

function renderPhotoStrip() {
  const strip = document.getElementById('report-photo-strip');
  strip.innerHTML = state.photos.map((p, i) => `
    <div class="photo-strip-item">
      <img src="${escapeHtml(p.dataUrl)}" alt="Ảnh ${i + 1}" />
    </div>
  `).join('');
}

// ── Voice Recording ───────────────────────────────────────────
function toggleRecording() {
  if (state.isRecording) {
    stopRecording();
  } else {
    startRecording();
  }
}

function startRecording() {
  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SpeechRecognition) {
    showToast('Trình duyệt không hỗ trợ ghi âm. Vui lòng gõ trực tiếp.');
    return;
  }

  const rec = new SpeechRecognition();
  rec.lang = 'vi-VN';
  rec.continuous = true;
  rec.interimResults = true;

  let finalTranscript = document.getElementById('voice-transcript').value;

  rec.onresult = (e) => {
    let interim = '';
    for (let i = e.resultIndex; i < e.results.length; i++) {
      const t = e.results[i][0].transcript;
      if (e.results[i].isFinal) {
        finalTranscript += (finalTranscript ? ' ' : '') + t;
      } else {
        interim = t;
      }
    }
    document.getElementById('voice-transcript').value = finalTranscript + (interim ? ' ' + interim : '');
  };

  rec.onerror = (e) => {
    showToast('Lỗi ghi âm: ' + e.error);
    stopRecording();
  };

  rec.onend = () => {
    if (state.isRecording) {
      // auto-restart to keep recording
      try { rec.start(); } catch (_) {}
    }
  };

  rec.start();
  state.recognition = rec;
  state.isRecording = true;
  setMicRecordingUI(true);
}

function stopRecording() {
  state.isRecording = false;
  if (state.recognition) {
    state.recognition.stop();
    state.recognition = null;
  }
  setMicRecordingUI(false);
}

function setMicRecordingUI(recording) {
  const btn = document.getElementById('btn-mic');
  const micIcon = document.getElementById('mic-icon');
  const stopIcon = document.getElementById('stop-icon');
  const label = document.getElementById('mic-label');
